    Session *session = malloc(sizeof(*session));
    char *mode_banner = malloc(64);

    if (session == NULL || mode_banner == NULL) {
        free(session);
        free(mode_banner);
        return NULL;
    }

    snprintf(mode_banner, 64, "mode:%d user:%s", mode, user);
    if (mode < 0 || mode > 2) {
